import { GlobalFonts } from '@napi-rs/canvas';
import { existsSync } from 'fs';
import { fileURLToPath } from 'url';
import { dirname, join, resolve } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));

export const DEFAULT_CFG = {
    W: 500, H: 500,
    BOX_W: 500, BOX_H: 500,
    BOX_PAD: 20,
    LINE_H: 1.08,
    BASELINE_ADJ: 0.75,
    FONT_NAME: 'Arial Narrow',
    FONT_WEIGHT: 400,
    FALLBACK_FONT: 'Arial, sans-serif',
    FS_MIN: 8,
    FS_MAX: 130,
    BLUR: 2,
    C_BG: '#ffffff',
    C_BOX: '#ffffff', 
    C_TEXT: '#000000',
    fontPaths: [],
};

/**
 * Merge default config with custom options.
 * Supports: bgColor, boxColor, textColor, blur, fontSize, padding, etc.
 * @param {object} options - Custom options to override defaults
 * @returns {object} Merged config
 */
export function resolveConfig(options = {}) {
    return {
        ...DEFAULT_CFG,
        C_BG: options.bgColor ?? options.bg ?? options.backgroundColor ?? DEFAULT_CFG.C_BG,
        C_BOX: options.boxColor ?? options.box ?? options.boxBackgroundColor ?? DEFAULT_CFG.C_BOX,        C_TEXT: options.textColor ?? options.text ?? options.fontColor ?? DEFAULT_CFG.C_TEXT,
        BLUR: options.blur ?? options.blurRadius ?? DEFAULT_CFG.BLUR,
        FS_MIN: options.fontSizeMin ?? DEFAULT_CFG.FS_MIN,
        FS_MAX: options.fontSizeMax ?? options.maxFontSize ?? DEFAULT_CFG.FS_MAX,
        BOX_PAD: options.padding ?? options.pad ?? DEFAULT_CFG.BOX_PAD,
        LINE_H: options.lineHeight ?? DEFAULT_CFG.LINE_H,
        BASELINE_ADJ: options.baselineAdjust ?? DEFAULT_CFG.BASELINE_ADJ,
        W: options.width ?? DEFAULT_CFG.W,
        H: options.height ?? DEFAULT_CFG.H,
        BOX_W: options.boxWidth ?? DEFAULT_CFG.BOX_W,
        BOX_H: options.boxHeight ?? DEFAULT_CFG.BOX_H,
        FONT_WEIGHT: options.fontWeight ?? DEFAULT_CFG.FONT_WEIGHT,
        fontPaths: options.fontPaths ?? DEFAULT_CFG.fontPaths,
    };
}

let _fontsReady = false;

/**
 * Register Arial Narrow from the first candidate path that exists.
 * @param {string[]} extraFontPaths
 */
export function registerFonts(extraFontPaths = []) {
    if (_fontsReady) return;
    _fontsReady = true;

    const candidates = [
        ...extraFontPaths.map(p => resolve(process.cwd(), p)),
        resolve(process.cwd(), 'assets/arialnarrow.ttf'),
        resolve(process.cwd(), 'assets/arial_narrow-webfont.woff'),
        join(__dirname, '../assets/arialnarrow.ttf'),
        join(__dirname, '../../assets/arialnarrow.ttf'),
        join(__dirname, '../assets/arial_narrow-webfont.woff'),
        join(__dirname, '../../assets/arial_narrow-webfont.woff'),
    ];

    for (const p of candidates) {
        if (!existsSync(p)) continue;
        try {
            GlobalFonts.registerFromPath(p, DEFAULT_CFG.FONT_NAME);
            if (GlobalFonts.has(DEFAULT_CFG.FONT_NAME)) {
                console.log(`✅ Font registered: ${p}`);
                return;
            }
        } catch {}
    }

    console.warn('⚠️ Arial Narrow not found, falling back to Arial.');
}

/**
 * Build a CSS font string for canvas.
 * @param {number} size
 * @param {string} fontName
 * @param {number} fontWeight
 * @param {string} fallback
 * @returns {string}
 */
export function fontString(size, fontName, fontWeight, fallback) {
    const family = GlobalFonts.has(fontName)
        ? `"${fontName}", ${fallback}`
        : fallback;
    return `${fontWeight} ${size}px ${family}`;
}